#include <iostream>
#include <cstring>
using namespace std;
int main()
{
    string word,sent;
    getline(cin,word);
    getline(cin,sent);
    int count=0,loca=0;
    word=" "+word+" ";
    sent=" "+sent+" ";
    for (int i = 0; i <=sent.size()-1; i++)
    {
        if (sent[i]>='A'&&sent[i]<='Z')
        {
            sent[i]+=32;
        }
    }
    for (int i = 0; i <=word.size()-1; i++)
    {
        if (word[i]>='A'&&word[i]<='Z')
        {
            word[i]+=32;
        }
    }
    if(sent.find(word)==-1)
    {
        cout<<"-1";
        return 0;
    }
    while (sent.find(word,loca)!=-1)
    {
        count++;
        loca=sent.find(word,loca)+1;
    }
    cout<<count<<" "<<sent.find(word);
    return 0;
}
